const plugin = {
  meta: {
    name: "svelte",
  },
  rules: {
    "valid-compile": {
      create(context) {
        return {
          Program(node) {
            const services = context.sourceCode.parserServices;
            const styleContext =
              typeof services.getStyleContext === "function"
                ? services.getStyleContext()
                : null;
            const parserOptions = context.languageOptions.parserOptions;
            const settings = context.settings;
            const nestedParser = parserOptions.parser;

            context.report({
              node,
              message: [
                `packagePlugin: ${context.id === "svelte/valid-compile"}`,
                `packageParser: ${context.languageOptions.parser?.name === "svelte-eslint-parser"}`,
                `isSvelte: ${services.isSvelte === true}`,
                `parseContext: ${services.svelteParseContext?.kind === "component"}`,
                `styleContext: ${Array.isArray(styleContext?.attrs) && styleContext.attrs.includes("class")}`,
                `projectService: ${parserOptions.projectService === true}`,
                `extraFileExtensions: ${Array.isArray(parserOptions.extraFileExtensions) && parserOptions.extraFileExtensions.includes(".svelte")}`,
                `nestedParser: ${typeof nestedParser?.parseForESLint === "function"}`,
                `svelteConfigFn: ${typeof parserOptions.svelteConfig?.preprocess === "function"}`,
                `settingsCompileDev: ${settings.svelte?.compileOptions?.dev === true}`,
                `settingsRoutes: ${settings.svelte?.kit?.files?.routes === "src/routes"}`,
                `wholeFile: ${context.sourceCode.text.includes('<h1 class="greeting">Hello {name}</h1>')}`,
              ].join("; "),
            });
          },
        };
      },
    },
  },
  configs: {
    recommended: {
      jsPlugins: ["eslint-plugin-svelte"],
      rules: {
        "svelte/valid-compile": "error",
      },
    },
  },
};

export default plugin;
